// ═══════════════════════════════════════════════════════════════
// Session Buttons — Drain Queue + Simulate Session End
// ═══════════════════════════════════════════════════════════════

import { pulseEdge } from './learning-graph';
import { showMcpOutput } from './toast';

const BRIDGE_EDGES = [
  'eng_hook_handler\u2192eng_memory_bridge',
  'eng_auto_memory\u2192eng_memory_bridge',
  'eng_memory_bridge\u2192db_memory',
];

export function initSessionButtons() {
  // Drain Queue
  document.getElementById('session-drain-btn')?.addEventListener('click', async () => {
    const btn = document.getElementById('session-drain-btn')!;
    btn.textContent = '\u23F3 Draining...';
    btn.setAttribute('disabled', '');
    try {
      const res = await fetch('/api/session/drain', { method: 'POST' });
      const data = await res.json();
      btn.textContent = data.ok ? `\u2713 Drained ${data.drained}` : '\u2717 Drain';
      showMcpOutput(`Drained ${data.drained} queued events`, data.ok);
    } catch {
      btn.textContent = '\u2717 Drain';
    }
    btn.removeAttribute('disabled');
    setTimeout(() => { btn.textContent = '\uD83D\uDCA5 Drain Queue'; }, 4000);
  });

  // Simulate Session End
  document.getElementById('session-end-btn')?.addEventListener('click', async () => {
    const btn = document.getElementById('session-end-btn')!;
    btn.textContent = '\u23F3 Session End...';
    btn.setAttribute('disabled', '');
    try {
      const res = await fetch('/api/session/end-sim', { method: 'POST' });
      const data = await res.json();
      btn.textContent = data.ok ? '\u2713 Done' : '\u26A0 Partial';
      if (data.ok) {
        for (const ek of BRIDGE_EDGES) pulseEdge(ek, 0.9);
      }
      const summary = (data.results || []).map((r: { step: string; ok: boolean; output?: string; error?: string }) =>
        `${r.ok ? '\u2713' : '\u2717'} ${r.step}: ${r.output || r.error || ''}`
      ).join('\n');
      showMcpOutput(summary, data.ok);
    } catch {
      btn.textContent = '\u2717 Failed';
    }
    btn.removeAttribute('disabled');
    setTimeout(() => { btn.textContent = '\u26A0 Session End'; }, 6000);
  });
}
