// ═══════════════════════════════════════════════════════════════
// Side Panel — Type-specific node drill-down
// ═══════════════════════════════════════════════════════════════

interface NodeData {
  id: string; label: string; type: string; tier: number;
  signals: { exists: boolean; healthy: boolean; active: boolean };
  meta: { path?: string; table?: string; rowCount?: number; fileSize?: number; lastMod?: string; description: string; tier: string; archTier?: string; statusNote?: string; patchRef?: string; phantom?: boolean };
  onDemand?: boolean;
  dormant?: boolean;
  phantom?: boolean;
  deprecated?: boolean;
  logKeys?: string[];
  matchers?: Array<{ pattern: string; handler: string }>;
}

const TYPE_COLORS: Record<string, string> = {
  trigger: '#f59e0b', script: '#3b82f6', engine: '#8b5cf6',
  store_db: '#10b981', store_json: '#14b8a6', config: '#6b7280',
  model: '#eab308', service: '#06b6d4',
};

// ── Open / Close ───────────────────────────────────────────────

let currentNodeId: string | null = null;

export function closeSidePanel() {
  document.getElementById('side-panel')!.classList.remove('open');
}

export async function openSidePanel(node: NodeData) {
  const panel = document.getElementById('side-panel')!;
  const title = document.getElementById('sp-title')!;
  const body = document.getElementById('sp-body')!;

  currentNodeId = node.id;
  title.innerHTML = `<span style="color:${TYPE_COLORS[node.type] || '#fff'}">${node.label}</span>`;
  body.innerHTML = '<div style="color:var(--text-dim)">Loading...</div>';
  panel.classList.add('open');

  try {
    const res = await fetch(`/api/node/${node.id}`);
    const data = await res.json();
    body.innerHTML = renderDetail(data.node, data.detail);
    requestAnimationFrame(() => { attachActionHandlers(); attachMcpHandlers(); });
  } catch (err) {
    body.innerHTML = `<div style="color:var(--color-missing)">Failed to load: ${err}</div>`;
  }
}

// ── Table expand handler (for store_db multi-table view) ──────

(window as any).__expandTable = async function(row: HTMLElement, tableName: string) {
  const detailEl = row.nextElementSibling as HTMLElement;
  if (!detailEl) return;

  // Toggle collapse
  if (detailEl.style.display !== 'none') {
    detailEl.style.display = 'none';
    row.querySelector('.tbl-arrow')!.textContent = '▶';
    return;
  }

  // Expand
  row.querySelector('.tbl-arrow')!.textContent = '▼';
  detailEl.style.display = 'block';
  detailEl.innerHTML = '<div style="color:var(--text-dim);padding:4px 8px">Loading...</div>';

  try {
    const res = await fetch(`/api/node/${currentNodeId}?table=${encodeURIComponent(tableName)}`);
    const data = await res.json();
    const d = data.detail;

    let html = '';
    if (d.schema?.length) {
      html += '<div style="font-weight:600;margin:4px 0">Schema</div>';
      html += '<table class="data"><tr><th>Column</th><th>Type</th></tr>';
      for (const col of d.schema) {
        html += `<tr><td>${col.name}</td><td>${col.type || 'any'}</td></tr>`;
      }
      html += '</table>';
    }
    if (d.preview?.length) {
      html += `<div style="font-weight:600;margin:8px 0 4px">Last ${d.preview.length} rows</div>`;
      html += '<pre class="code">' + escapeHtml(JSON.stringify(d.preview, null, 2).slice(0, 20000)) + '</pre>';
    } else {
      html += '<div style="color:var(--text-dim)">Table is empty</div>';
    }
    detailEl.innerHTML = html;
  } catch (err) {
    detailEl.innerHTML = `<div style="color:var(--color-missing)">Failed to load: ${err}</div>`;
  }
};

// ── Init close button ──────────────────────────────────────────

document.getElementById('sp-close')?.addEventListener('click', closeSidePanel);

