  wrk_deepdive:     { worker: 'deepdive',    label: 'Run Deep Dive' },
  wrk_document:     { worker: 'document',    label: 'Run Auto-Document' },
  wrk_refactor:     { worker: 'refactor',    label: 'Run Refactor' },
  wrk_benchmark:    { worker: 'benchmark',   label: 'Run Benchmark' },
